cd /tmp/sv-66336ed3e4cb4d25a897c1aee702c7ac/moderate-version-conflicts && dotnet list package --format json 2>/dev/null | python3 -c "import sys,json; data=json.load(sys.stdin); json.dump(data,open('after-cpm-packages.json','w'),indent=2)" && python3 -c "
import json
baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result.setdefault(name, {})[pkg['id']] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = extract(baseline)
a = extract(after)

print('=== Package Comparison ===')
changed = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bv = b.get(proj,{}).get(pkg, (None,None))
        av = a.get(proj,{}).get(pkg, (None,None))
        if bv[1] != av[1]:
            changed.append((proj, pkg, bv[1], av[1]))
        else:
            unchanged.append((proj, pkg, av[1]))

if changed:
    print('CHANGES:')
    for proj, pkg, old, new in changed:
        print(f'  {proj}/{pkg}: {old} -> {new}')
else:
    print('No changes!')

print(f'\nUnchanged: {len(unchanged)} package-project pairs')
"

